// Modern Express API with TypeScript
import express, { Request, Response, NextFunction } from 'express';
import cors from 'cors';
import helmet from 'helmet';

const app = express();
const PORT = process.env.PORT || 3000;

// Middleware
app.use(helmet()); // Security headers
app.use(cors()); // Enable CORS
app.use(express.json()); // Parse JSON bodies

// Request logging middleware
app.use((req: Request, res: Response, next: NextFunction) => {
  console.log(`${req.method} ${req.path}`);
  next();
});

// Types
interface User {
  id: number;
  name: string;
  email: string;
}

// In-memory store (use database in production)
const users: User[] = [];
let nextId = 1;

// Routes
app.get('/api/users', (req: Request, res: Response) => {
  res.json(users);
});

app.post('/api/users', (req: Request, res: Response) => {
  const { name, email } = req.body;

  if (!name || !email) {
    return res.status(400).json({ error: 'Name and email required' });
  }

  const user: User = { id: nextId++, name, email };
  users.push(user);
  res.status(201).json(user);
});

app.get('/api/users/:id', (req: Request, res: Response) => {
  const user = users.find(u => u.id === parseInt(req.params.id));

  if (!user) {
    return res.status(404).json({ error: 'User not found' });
  }

  res.json(user);
});

// Error handling middleware
app.use((err: Error, req: Request, res: Response, next: NextFunction) => {
  console.error(err.stack);
  res.status(500).json({ error: 'Something went wrong!' });
});

// Start server
app.listen(PORT, () => {
  console.log(`Server running on http://localhost:${PORT}`);
});

// Type aliases and interfaces
type ID = string | number;

interface User {
  id: ID;
  name: string;
  email: string;
  role: 'admin' | 'user' | 'guest'; // Union type
  createdAt: Date;
}

// Generics - reusable type-safe functions
function getFirstItem<T>(arr: T[]): T | undefined {
  return arr[0];
}

const firstNumber = getFirstItem([1, 2, 3]); // Type: number | undefined
const firstName = getFirstItem(['Alice', 'Bob']); // Type: string | undefined

// Utility types
type PartialUser = Partial<User>; // All properties optional
type UserWithoutEmail = Omit<User, 'email'>; // Remove email
type UserNameAndEmail = Pick<User, 'name' | 'email'>; // Only these props
type ReadonlyUser = Readonly<User>; // All properties readonly

// Type guards
function isAdmin(user: User): user is User & { role: 'admin' } {
  return user.role === 'admin';
}

// Discriminated unions
type ApiResponse<T> = 
  | { status: 'success'; data: T }
  | { status: 'error'; error: string }
  | { status: 'loading' };

function handleResponse<T>(response: ApiResponse<T>) {
  switch (response.status) {
    case 'success':
      console.log(response.data); // TypeScript knows .data exists
      break;
    case 'error':
      console.error(response.error); // TypeScript knows .error exists
      break;
    case 'loading':
      console.log('Loading...'); // No data or error property
      break;
  }
}

// Async/await with types
async function fetchUser(id: ID): Promise<User> {
  const response = await fetch(`/api/users/${id}`);
  if (!response.ok) {
    throw new Error('Failed to fetch user');
  }
  return await response.json();
}

